#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI N=20;
int n,p[N];
string s[N][N];
map<char,int> m;
signed main(void)
{
    n=read();
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            cin>>s[i][j];
        }
    }
    FOR(i,2,n)
    {
        int sum=0;
        FOR(j,1,n)
        {
            if(s[i][j].size()==2) sum++;
        }
        p[i]=sum;
        m.insert({s[i][1][0],sum});
    }
    FOR(i,2,n)
    {
        FOR(j,2,n)
        {
            int a=p[i],b=p[j],c;
            if(s[i][j].size()==2) c=m[s[i][j][0]]*(n-1)+m[s[i][j][1]];
            else c=m[s[i][j][0]];
            if(c!=a+b)
            {
                printf("ERROR!\n");
                return 0;
            }
        }
    }
    FOR(i,2,n) cout<<s[i][1]<<"="<<p[i]<<" ";
    printf("\n%lld",n-1);
    return false;
}
